import{_ as r,c as t,o as a,ag as o}from"./chunks/framework.D4Vqf8I7.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"docs/wi/games/psx.md","filePath":"docs/wi/games/psx.md","lastUpdated":1784203520000}'),s={name:"docs/wi/games/psx.md"};function n(i,e,p,l,h,c){return a(),t("div",null,e[0]||(e[0]=[o('<p>title: &quot;Exploring Tokimeki Memorial: Tools and resources for PSX reverse-engineering&quot; source: &quot;<a href="https://tetracorp.github.io/tokimeki-memorial/methods/tools-resources.html#psx-file-format-conversion-tools" target="_blank" rel="noreferrer">https://tetracorp.github.io/tokimeki-memorial/methods/tools-resources.html#psx-file-format-conversion-tools</a>&quot; author: published: created: 2026-07-13 description: tags:</p><ul><li>&quot;clippings&quot;</li></ul><p>The following is a list of tools and documents useful for analyzing, modding or translating PlayStation games. Many of them are conveniently available in Linux by a package manager like <code>apt</code>.</p><h3 id="psx-file-format-conversion-tools" tabindex="-1">PSX file format conversion tools <a class="header-anchor" href="#psx-file-format-conversion-tools" aria-label="Permalink to &quot;PSX file format conversion tools&quot;">​</a></h3><p><a href="https://github.com/m35/jpsxdec" target="_blank" rel="noreferrer">jPSXdec</a></p><p>Audio/video convertor which can extract PSX file formats from a disc image and build an index of file locations. Converts XA, STR, TIM.</p><p><a href="https://github.com/simias/psxsdk" target="_blank" rel="noreferrer">psxsdk</a></p><p>Unofficial SDK for creating PlayStation games. Includes source for some conversion tools for PSX formats (ISO/BIN, WAV/VAG. TIM/BMP).</p><h3 id="cd-rom-tools" tabindex="-1">CD-ROM tools <a class="header-anchor" href="#cd-rom-tools" aria-label="Permalink to &quot;CD-ROM tools&quot;">​</a></h3><p><a href="https://github.com/cebix/psximager" target="_blank" rel="noreferrer">PSXImager</a></p><p>Three tools: psxrip (extract files and disc metadata from BIN/CUE), psxbuild (creates a disc image), and psxinject (modify a disc image). Unfortunately doesn’t provide a build, and has difficulty with some images.</p><p>AcetoneISO</p><p>Linux tool to mount, extract and burn single-track ISO and BIN.</p><p><a href="https://www.poweriso.com/" target="_blank" rel="noreferrer">PowerISO</a></p><p>Commercial Windows/Linux CD-ROM authoring tool.</p><p>ccd2iso</p><p>Linux tool to convert IMG to ISO.</p><p>iat</p><p>Linux tool to convert various formats to ISO.</p><p>bchunk</p><p>Linux tool to convert BIN/CUE to ISO and CD audio to WAV. Supports PSX 2336-byte chunk tracks.</p><p>isoinfo</p><p>Linux tool to list contents of ISO files.</p><p><a href="https://github.com/putnam/binmerge" target="_blank" rel="noreferrer">binmerge</a></p><p>Python script to combine a multi-track BIN/CUE into one.</p><h3 id="disassemblers-and-decompilers" tabindex="-1">Disassemblers and decompilers <a class="header-anchor" href="#disassemblers-and-decompilers" aria-label="Permalink to &quot;Disassemblers and decompilers&quot;">​</a></h3><p><a href="https://ghidra-sre.org/" target="_blank" rel="noreferrer">Ghidra</a></p><p>NSA’s disassembler/decompiler, released to the public in 2019.</p><p><a href="https://www.radare.org/" target="_blank" rel="noreferrer">Radare2</a></p><p>Free and open-source disassembly tool.</p><p><a href="https://www.hex-rays.com/products/ida/" target="_blank" rel="noreferrer">IDA Pro</a></p><p>Commercial decompiler. There’s a <a href="https://www.hex-rays.com/products/ida/support/download_freeware/" target="_blank" rel="noreferrer">free</a> version but it only supports x86/64 and not MIPS (PSX). <a href="https://github.com/lab313ru/ghidra_psx_ldr" target="_blank" rel="noreferrer">ghidra_psx_ldr</a></p><p>PSX executable add-on for Ghidra.</p><p><a href="https://www.beneaththewaves.net/Software/This_Dust_Remembers_What_It_Once_Was.html" target="_blank" rel="noreferrer">This Dust Remembers What It Once Was</a></p><p>Tools for aiding PSX analysis with Ghidra. Convert PSX-EXE to ELF and parse PsyQ.SYM files.</p><h3 id="emulators-and-debuggers" tabindex="-1">Emulators and debuggers <a class="header-anchor" href="#emulators-and-debuggers" aria-label="Permalink to &quot;Emulators and debuggers&quot;">​</a></h3><p><a href="https://mednafen.github.io/documentation/psx.html" target="_blank" rel="noreferrer">Mednafen</a></p><p>Emulator with a powerful debugger.</p><p><a href="https://problemkaputt.de/psx.htm" target="_blank" rel="noreferrer">No$psx</a></p><p>PSX emulator and debugger.</p><p><a href="https://www.epsxe.com/" target="_blank" rel="noreferrer">ePSXe</a></p><p>PSX emulator.</p><h3 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><p><a href="https://problemkaputt.de/psx-spx.htm" target="_blank" rel="noreferrer">Nocash PSX Specifications</a></p><p>Description of PSX systems from the author of an emulator.</p><p><a href="https://www.raphnet.net/electronique/psx_adaptor/Playstation.txt" target="_blank" rel="noreferrer">Everything You Have Always Wanted to Know about the Playstation But Were Afraid to Ask v1.1</a></p><p>A collection of documentation about the PSX hardware and history from 2000 (originally <a href="https://web.archive.org/web/20011211221846/http://www.execpc.com/~halkun/PSX/index.html" target="_blank" rel="noreferrer">here</a>).</p><p><a href="https://www.retroreversing.com/ps1/" target="_blank" rel="noreferrer">Introduction to Hacking the Sony Playstation One</a></p><p>RetroReversing’s articles on the PSX.</p><p><a href="https://psx.arthus.net/sdk/NetYaroze/Net%20Yaroze%20Official%20-%20Startup%20Guide.pdf" target="_blank" rel="noreferrer">Net Yaroze Startup Guide</a></p><p>Documentation for the official Net Yaroze PSX devkit.</p><h3 id="development-and-miscellaneous" tabindex="-1">Development and miscellaneous <a class="header-anchor" href="#development-and-miscellaneous" aria-label="Permalink to &quot;Development and miscellaneous&quot;">​</a></h3><p><a href="https://www.romhacking.net/?page=utilities&amp;category=&amp;platform=17&amp;game=&amp;author=&amp;os=&amp;level=&amp;perpage=200&amp;title=&amp;desc=&amp;utilsearch=Go" target="_blank" rel="noreferrer">Romhacking.net PSX Utilities</a></p><p>A list of PSX utilities for various platforms.</p><p><a href="https://psx.arthus.net/" target="_blank" rel="noreferrer">psx.arthus.net</a></p><p>A collection of PSX development resources.</p><p><a href="https://ps1.consoledev.net/" target="_blank" rel="noreferrer">PSX Links</a></p><p>Another collection of documentation and resources.</p><p><a href="https://loveemu.hatenablog.com/archive/category/PSX" target="_blank" rel="noreferrer">loveemu labo’s PSX articles</a></p><p>Some articles.</p><hr><p><a href="https://tetracorp.github.io/tokimeki-memorial/" target="_blank" rel="noreferrer">« Back to index page</a></p>',62)]))}const u=r(s,[["render",n]]);export{m as __pageData,u as default};
